1	// src/magazine/digest.ts — Assemble a daily issue JSON from raw ingested
2	// bookmarks. The heart of the magazine.
3	//
4	// Pipeline:
5	//   1. Load today's raw JSONL (ingest.ts wrote it).
6	//   2. Group items by folder → sections.
7	//   3. Per item, ask an LLM for { summary, whyItMatters }. Parallel up to 5.
8	//   4. Pick Old Gold candidates from the archive (>30d old, not recently
9	//      resurfaced) and ask the LLM to choose 5 with thematic ties.
10	//   5. Ask the LLM for a one-line "signal" headline.
11	//   6. Assemble the issue JSON per the locked data contract and write to
12	//      ~/.mame/magazine/issues/YYYY-MM-DD.json.
13	//
14	// LLM model: persona.models.complex if set, else persona.models.default.
15	
16	import fs from "fs";
17	import {
18	  completeSimple,
19	  getModel,
20	  type Context,
21	  type KnownProvider,
22	  type AssistantMessage,
23	} from "@mariozechner/pi-ai";
24	import { loadConfig, loadPersona, type PersonaConfig } from "../config.js";
25	import { parseModelString } from "../model-router.js";
26	import {
27	  archiveStats,
28	  issueJsonPath,
29	  loadState,
30	  pickOldGoldCandidates,
31	  rawJsonlPath,
