103	
104	export interface MagazineIssue {
105	  issueNumber: number;
106	  date: string;
107	  volume: number;
108	  masthead: IssueMasthead;
109	  signal: string;
110	  sections: IssueSection[];
111	  /** Designated top story of the issue — first item of the largest section.
112	   *  Null when there are no items at all. Convenience derived from sections. */
113	  featured: IssueItemWithFolder | null;
114	  /** All other items, flattened in section order, folder inlined. */
115	  rest: IssueItemWithFolder[];
