132	// ---------------------------------------------------------------------------
133	// Entry point
134	// ---------------------------------------------------------------------------
135	
136	export async function generateDailyDigest(opts: GenerateOptions = {}): Promise<GenerateResult> {
137	  const startMs = Date.now();
138	  const cfg = loadConfig();
139	  const date = opts.date ?? todayISO(cfg.timezone);
140	  const personaName = opts.personaName ?? "default";
141	  const persona = loadPersona(personaName);
142	
143	  log.info({ date, persona: personaName }, "digest generation starting");
144	
145	  const records = loadRawJsonl(date);
146	  if (records.length === 0) {
147	    throw new Error(`No raw bookmarks found for ${date} at ${rawJsonlPath(date)}. Run ingest first.`);
148	  }
149	
150	  const piModel = resolveModel(persona);
151	
152	  // 1. Per-item summarization (parallel)
153	  const summarized = await summarizeItems(records, piModel);
154	
155	  // 2. Group into sections by folder
156	  const sections = groupIntoSections(summarized);
157	
158	  // 2b. Derive a flattened scan-grid view — featured item + rest.
159	  //     Featured = first item of first (largest) section. Sections is
160	  //     already sorted largest-first in groupIntoSections.
161	  const flatItems: IssueItemWithFolder[] = sections.flatMap((s) =>
162	    s.items.map((i) => ({ ...i, folder: s.title }))
163	  );
164	  const featured: IssueItemWithFolder | null = flatItems[0] ?? null;
165	  const rest: IssueItemWithFolder[] = flatItems.slice(1);
166	
167	  // 3. Old Gold
168	  const oldGold = await pickAndExplainOldGold(records, summarized, piModel);
169	
170	  // 4. Signal headline
171	  const signal = await generateSignal(summarized, piModel);
172	
173	  // 5. Stats + masthead
174	  const archive = archiveStats();
175	  const topCategory =
176	    sections
177	      .map((s) => ({ title: s.title, count: s.items.length }))
178	      .sort((a, b) => b.count - a.count)[0]?.title ?? "(none)";
179	
180	  const state = loadState();
181	  const issueNumber = state.nextIssueNumber;
182	  state.nextIssueNumber = issueNumber + 1;
183	  const now = new Date();
184	  for (const og of oldGold) {
185	    state.oldGoldResurfaceLog[og.id] = now.toISOString();
186	  }
187	  saveState(state);
188	
189	  const runtimeMs = Date.now() - startMs;
190	
191	  const issue: MagazineIssue = {
192	    issueNumber,
193	    date,
194	    volume: 1,
