/* ============================================================
 * dAIly digest — magazine stylesheet
 *
 * Editorial print register layered on Anthropic.com/news's clean
 * structural foundation. Display: Bodoni Moda (variable optical-size
 * didone). Body: Hanken Grotesk (humanist grotesque). Warm cream paper,
 * near-black ink, weathered newsprint-red accent. Why-it-matters runs
 * as a continuation italic with an inline red flag — no zoning.
 *
 * LAYOUT — magazine front:
 *   Masthead → Signal epigraph → Featured row (featured + Old Gold aside)
 *   → Front meta line → Grid (first item spans cols) → Old Gold archive
 *   pocket → Colophon.
 *
 * TYPOGRAPHY RULE (load-bearing — read before changing anything):
 *   Bodoni Moda is ONLY used at sizes ≥ 2rem OR as single-glyph
 *   decoration. Didone's thin-thick contrast collapses at smaller
 *   sizes and makes real reading hard. Everywhere else is Hanken.
 *   Four Bodoni usages survive this rule:
 *     1. .title (wordmark — logo territory)
 *     2. .dispatch-number (single-glyph editorial ornament)
 *     3. .featured-title (>=2rem) and .dispatch-title (upright, >=1.6rem peak 2.4rem)
 *     4. .featured-summary::first-letter (drop cap, 4.8rem)
 * ============================================================ */

:root {
  /* ---- Color (OKLCH) ---- */
  --paper:        oklch(98%  0.008  85);
  --paper-warm:   oklch(96%  0.015  82);
  --paper-deep:   oklch(94%  0.020  82);
  --ink:          oklch(20%  0.008  60);
  --ink-soft:     oklch(35%  0.010  60);
  --ink-muted:    oklch(50%  0.010  60);
  --ink-faint:    oklch(72%  0.010  70);
  --ink-ghost:    oklch(84%  0.010  70);
  --rule:         oklch(86%  0.014  80);
  --rule-strong:  oklch(70%  0.016  70);
  --accent:       oklch(44%  0.14   30);
  --accent-soft:  oklch(58%  0.12   35);

  /* ---- Type ---- */
  --display: "Bodoni Moda", "Bodoni 72", "Didot", "GFS Didot", Georgia, serif;
  --body:    "Hanken Grotesk", "Helvetica Neue", "Inter", system-ui, -apple-system, sans-serif;

  /* ---- Spacing (4pt scale) ---- */
  --space-2xs: 0.25rem;
  --space-xs:  0.5rem;
  --space-sm:  0.75rem;
  --space-md:  1rem;
  --space-lg:  1.5rem;
  --space-xl:  2rem;
  --space-2xl: 3rem;
  --space-3xl: 4rem;
  --space-4xl: 6rem;
  --space-5xl: 8rem;

  /* ---- Reading widths ---- */
  --reading:    36rem;    /* ~62ch body column */
  --frame:      52rem;    /* narrow frame */
  --frame-wide: 64rem;    /* grid-scale frame */
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; }
html, body, h1, h2, h3, h4, p, ol, ul, li, figure, blockquote { margin: 0; padding: 0; }
ol, ul { list-style: none; }
hr { border: 0; }
img { display: block; max-width: 100%; }

html {
  font-size: clamp(16px, 0.95vw + 0.5rem, 18px);
  background: var(--paper);
  color: var(--ink);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  font-feature-settings: "kern", "liga";
}

body {
  font-family: var(--body);
  font-weight: 400;
  line-height: 1.6;
  max-width: 68rem;
  margin: 0 auto;
  padding: clamp(1.5rem, 4vw, 3rem) clamp(1rem, 4vw, 2.5rem) var(--space-5xl);
}

/* ============================================================
 * Links
 * ============================================================ */
a {
  color: inherit;
  text-decoration-line: underline;
  text-decoration-thickness: 0.04em;
  text-underline-offset: 0.18em;
  text-decoration-color: var(--ink-faint);
  transition: color 180ms ease-out, text-decoration-color 180ms ease-out;
}
a:hover {
  color: var(--accent);
  text-decoration-color: var(--accent);
}
a:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 3px;
  border-radius: 1px;
}

/* ============================================================
 * Masthead
 * ============================================================ */
.masthead {
  border-top: 3px solid var(--ink);
  border-bottom: 1px solid var(--ink);
  padding: var(--space-md) 0 var(--space-lg);
  margin-bottom: var(--space-lg);
  display: grid;
  grid-template-columns: 1fr auto 1fr;
  align-items: end;
  gap: var(--space-lg);
}

.dateline,
.issue-meta {
  font-family: var(--body);
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--ink-muted);
  line-height: 1.4;
}

.dateline { justify-self: start; }
.issue-meta {
  justify-self: end;
  text-align: right;
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  flex-wrap: wrap;
  justify-content: flex-end;
}
.issue-meta .dot { color: var(--ink-faint); }

.title {
  font-family: var(--display);
  font-weight: 400;
  font-size: clamp(3rem, 9vw, 6rem);
  line-height: 0.92;
  letter-spacing: -0.025em;
  text-align: center;
  font-variation-settings: "opsz" 96;
}

.title .ink { color: var(--ink); }
.title .ai {
  color: var(--accent);
  font-style: italic;
  font-weight: 500;
  font-feature-settings: "ss01";
  letter-spacing: -0.04em;
  margin: 0 -0.06em 0 -0.04em;
}

/* ============================================================
 * Signal — the daily editorial epigraph
 * ============================================================ */
.signal {
  max-width: var(--reading);
  margin: var(--space-2xl) auto var(--space-3xl);
  text-align: center;
}

.signal-mark {
  font-family: var(--display);
  color: var(--accent);
  font-size: 1.75rem;
  margin-bottom: var(--space-sm);
  line-height: 1;
}

.signal-text {
  font-family: var(--body);
  font-style: italic;
  font-weight: 500;
  font-size: clamp(1.3rem, 2.6vw, 1.75rem);
  line-height: 1.38;
  color: var(--ink);
  text-wrap: balance;
}

/* ============================================================
 * Featured row — 2-col split: featured (left) + Old Gold aside (right)
 * ============================================================ */
.featured-row {
  max-width: var(--frame-wide);
  margin: 0 auto var(--space-3xl);
  display: grid;
  grid-template-columns: 1.65fr 1fr;
  gap: var(--space-2xl);
  align-items: start;
}

@media (max-width: 860px) {
  .featured-row {
    grid-template-columns: 1fr;
    gap: var(--space-2xl);
  }
}

/* ---- Featured (the day's top story) ---- */
.featured {
  margin: 0;
}

.featured-hero {
  margin: 0 0 var(--space-lg);
  background: var(--paper-warm);
}
.featured-hero img {
  display: block;
  width: 100%;
  height: auto;
  max-height: min(56vh, 34rem);   /* cap on tall displays */
  object-fit: cover;
  object-position: center;
}

.featured-kicker {
  font-family: var(--body);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--accent);
  margin-bottom: var(--space-xs);
}

.featured-title {
  font-family: var(--display);
  font-weight: 500;
  font-size: clamp(2rem, 4.5vw, 2.8rem);
  line-height: 1.04;
  letter-spacing: -0.02em;
  margin: var(--space-sm) 0 var(--space-md);
  font-variation-settings: "opsz" 72;
  text-wrap: balance;
}
.featured-title a {
  text-decoration: none;
  color: var(--ink);
}
.featured-title a:hover {
  color: var(--accent);
  text-decoration: underline;
  text-decoration-thickness: 0.05em;
  text-underline-offset: 0.15em;
}

.featured-summary {
  font-family: var(--body);
  font-size: 1.05rem;
  line-height: 1.65;
  margin-bottom: var(--space-md);
  hanging-punctuation: first last;
  text-wrap: pretty;
}

/* Drop cap on featured summary — red Bodoni capital */
.featured-summary::first-letter {
  font-family: var(--display);
  font-weight: 500;
  font-style: normal;
  float: left;
  font-size: 4.6rem;
  line-height: 0.82;
  margin: 0.06em 0.08em -0.05em 0;
  color: var(--accent);
  font-variation-settings: "opsz" 96;
}

/* ============================================================
 * Old Gold aside — single callback on the right rail of featured-row
 * ============================================================ */
.old-gold-aside {
  background: var(--paper-deep);
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  /* subtle hairlines top and bottom to echo the archival-pocket register */
  border-top: 1px solid var(--rule-strong);
  border-bottom: 1px solid var(--rule-strong);
}

.old-gold-aside-kicker {
  font-family: var(--body);
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--accent);
  display: flex;
  align-items: center;
  gap: 0.4em;
}
.old-gold-aside-kicker .mark {
  font-family: var(--display);
  font-size: 1rem;
  line-height: 1;
  font-weight: 400;
  letter-spacing: 0;
}

.old-gold-aside-title {
  font-family: var(--body);
  font-weight: 600;
  font-style: italic;
  font-size: 1.05rem;
  line-height: 1.32;
  letter-spacing: -0.005em;
}
.old-gold-aside-title a {
  text-decoration: none;
  color: var(--ink);
}
.old-gold-aside-title a:hover {
  color: var(--accent);
  text-decoration: underline;
}

.old-gold-aside-summary {
  font-family: var(--body);
  font-size: 0.92rem;
  line-height: 1.55;
  color: var(--ink);
  hanging-punctuation: first last;
}

.old-gold-aside-resurface {
  font-family: var(--body);
  font-style: italic;
  font-size: 0.88rem;
  line-height: 1.5;
  color: var(--ink-soft);
  border-top: 1px solid var(--rule-strong);
  padding-top: var(--space-sm);
  margin-top: var(--space-xs);
}
.old-gold-aside-resurface .mark {
  color: var(--accent);
  font-style: normal;
  margin-right: 0.3em;
}

.old-gold-aside-meta {
  font-family: var(--body);
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--ink-faint);
  margin-top: var(--space-xs);
}
.old-gold-aside-meta a {
  color: var(--ink-muted);
  text-decoration: underline;
  text-decoration-color: var(--ink-faint);
  text-decoration-thickness: 0.04em;
  text-underline-offset: 0.18em;
  margin-right: var(--space-sm);
}

/* ============================================================
 * Front meta — a single muted line that announces the grid count
 * (replaces the prior "The Morning's Dispatch" section header)
 * ============================================================ */
.front-meta {
  max-width: var(--frame-wide);
  margin: 0 auto var(--space-lg);
  border-top: 1px solid var(--ink);
  padding-top: var(--space-sm);
  font-family: var(--body);
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--ink-muted);
  display: flex;
  align-items: baseline;
  gap: var(--space-sm);
  flex-wrap: wrap;
}
.front-meta .dot { color: var(--ink-faint); }

/* ============================================================
 * Front grid — scannable stack of the day's items
 * ============================================================ */
.front-grid {
  max-width: var(--frame-wide);
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(24rem, 1fr));
  gap: var(--space-2xl);
  padding: 0;
}

/* First item spans all columns — secondary feature, breaks the uniform grid */
.front-grid .front-item:first-child {
  grid-column: 1 / -1;
}

.front-item {
  display: flex;
  flex-direction: column;
  padding: 0 0 var(--space-xl);
  border-bottom: 1px solid var(--rule);
}

/* Spanner gets a slightly different internal layout: image left, text right */
@media (min-width: 860px) {
  .front-grid .front-item:first-child {
    display: grid;
    grid-template-columns: 1.1fr 1fr;
    gap: var(--space-xl);
    align-items: start;
  }
  .front-grid .front-item:first-child .item-hero {
    grid-row: 1 / span 6;
    margin: 0;
  }
  .front-grid .front-item:first-child .item-title {
    font-size: 1.4rem;
  }
  /* When spanner has no hero image, fall back to single column so the text
   * doesn't stretch across an empty grid track */
  .front-grid .front-item:first-child:not(:has(.item-hero)) {
    display: flex;
    flex-direction: column;
  }
}

/* Grid item hero thumbnail */
.front-item .item-hero {
  margin: 0 0 var(--space-md);
  aspect-ratio: 16 / 9;
  overflow: hidden;
  background: var(--paper-warm);
}
.front-item .item-hero img {
  width: 100%;
  height: 100%;
  max-height: none;
  object-fit: cover;
}

/* ---- Item meta: category tag + date, always rendered ---- */
.item-meta {
  font-family: var(--body);
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--ink-muted);
  margin-bottom: var(--space-sm);
  display: flex;
  gap: var(--space-sm);
  align-items: baseline;
  flex-wrap: wrap;
}
.item-category {
  color: var(--accent);
}
.item-category--unfiled {
  color: var(--ink-faint);
}
.item-date {
  color: var(--ink-faint);
  letter-spacing: 0.08em;
}
.item-category + .item-date::before {
  content: "·";
  margin-right: var(--space-xs);
  color: var(--ink-faint);
}

/* ---- Grid item title / summary / why ---- */
.front-item .item-title {
  font-family: var(--body);
  font-weight: 600;
  font-size: 1.1rem;
  line-height: 1.3;
  letter-spacing: -0.005em;
  margin-bottom: var(--space-sm);
  text-wrap: balance;
}
.front-item .item-title a {
  text-decoration: none;
  color: var(--ink);
}
.front-item .item-title a:hover {
  color: var(--accent);
  text-decoration: underline;
  text-decoration-thickness: 0.05em;
  text-underline-offset: 0.18em;
}

.front-item .item-summary {
  font-family: var(--body);
  font-size: 0.95rem;
  line-height: 1.55;
  color: var(--ink);
  margin-bottom: var(--space-sm);
  text-wrap: pretty;
  hanging-punctuation: first last;
}

.front-item .item-why {
  font-size: 0.88rem;
  line-height: 1.5;
  margin-top: var(--space-xs);
  margin-bottom: var(--space-sm);
  color: var(--ink-soft);
  max-width: none;
}

/* Source line — no longer pinned to bottom; sits naturally at content end */
.front-item .item-source {
  /* inherits .item-source base below */
}

/* ============================================================
 * Why-it-matters (used by featured and grid items)
 * ============================================================ */
.item-why {
  display: block;
  clear: left;
  font-family: var(--body);
  font-size: 0.98rem;
  line-height: 1.58;
  color: var(--ink-soft);
  margin: var(--space-sm) 0 var(--space-md);
  max-width: 62ch;
}
.item-why-label {
  display: inline;
  font-family: var(--body);
  font-weight: 700;
  font-size: 0.7rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--accent);
  margin-right: 0.35em;
  vertical-align: 0.05em;
}
.item-why-label::after {
  content: " —";
  color: var(--ink-muted);
  font-weight: 400;
  letter-spacing: 0;
}
.item-why-text {
  font-style: italic;
  color: var(--ink);
}

/* ============================================================
 * Source line (base for both featured and grid items)
 * ============================================================ */
.item-source {
  font-family: var(--body);
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--ink-muted);
  margin-top: var(--space-md);
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--space-sm);
}
.item-source a {
  color: var(--ink-muted);
  text-decoration: underline;
  text-decoration-thickness: 0.04em;
  text-underline-offset: 0.2em;
  text-decoration-color: var(--ink-faint);
}
.item-source-time {
  color: var(--ink-faint);
  letter-spacing: 0.08em;
}
.item-source-time::before {
  content: "·";
  margin-right: var(--space-sm);
  color: var(--ink-faint);
}

/* ============================================================
 * Old Gold archive pocket — full list below the grid
 * ============================================================ */
.dispatch-gold {
  max-width: var(--frame-wide);
  margin: var(--space-4xl) auto 0;
  background: var(--paper-deep);
  padding: var(--space-2xl) var(--space-xl);
  border-top: 1px solid var(--ink);
  border-bottom: 1px solid var(--ink);
}

.dispatch-header {
  display: grid;
  grid-template-columns: minmax(2.5rem, auto) 1fr;
  align-items: end;
  gap: clamp(0.75rem, 2vw, 1.25rem);
  padding-bottom: var(--space-md);
  margin-bottom: var(--space-xl);
  border-bottom: 1px solid var(--rule-strong);
}

.dispatch-number {
  font-family: var(--display);
  font-style: normal;
  font-weight: 400;
  color: var(--accent);
  font-size: clamp(1.8rem, 4vw, 2.4rem);
  line-height: 1;
  letter-spacing: -0.02em;
  user-select: none;
}

.dispatch-titling { padding-bottom: 0.15rem; }

.dispatch-title {
  font-family: var(--display);
  font-weight: 500;
  font-size: clamp(1.6rem, 3vw, 2.2rem);
  line-height: 1.05;
  letter-spacing: -0.015em;
  color: var(--ink);
  font-variation-settings: "opsz" 48;
}

.dispatch-gold .dispatch-subtitle {
  font-family: var(--body);
  font-style: italic;
  font-weight: 400;
  font-size: 0.95rem;
  letter-spacing: 0;
  text-transform: none;
  color: var(--ink-soft);
  line-height: 1.5;
  margin-top: var(--space-xs);
}

.items {
  max-width: var(--reading);
  margin: 0 auto;
}

.item {
  padding: var(--space-xl) 0;
  border-bottom: 1px solid var(--rule);
}
.item:last-child { border-bottom: 0; padding-bottom: 0; }
.item:first-child { padding-top: var(--space-md); }

.item-title {
  font-family: var(--body);
  font-weight: 600;
  font-size: 1.15rem;
  line-height: 1.32;
  letter-spacing: -0.005em;
  margin-bottom: var(--space-sm);
  text-wrap: balance;
}
.item-title a {
  text-decoration: none;
  color: var(--ink);
}
.item-title a:hover {
  color: var(--accent);
  text-decoration: underline;
}

.item-summary {
  font-family: var(--body);
  font-size: 1rem;
  line-height: 1.62;
  color: var(--ink);
  margin-bottom: var(--space-md);
  hanging-punctuation: first last;
  text-wrap: pretty;
}

.item-hero {
  display: block;
  margin: 0 0 var(--space-md);
  background: var(--paper-warm);
}
.item-hero img {
  display: block;
  width: 100%;
  height: auto;
  max-height: 42vh;
  object-fit: cover;
  object-position: center;
  background: var(--paper-warm);
}

/* Old Gold items */
.item-gold .item-title {
  font-family: var(--body);
  font-weight: 600;
  font-style: italic;
  font-size: 1.15rem;
}
.item-gold .item-hero img {
  max-height: 32vh;
}

.item-resurface {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  margin: var(--space-md) 0;
  padding-top: var(--space-md);
  border-top: 1px solid var(--rule-strong);
  font-family: var(--body);
  font-style: italic;
  font-weight: 400;
  font-size: 0.98rem;
  line-height: 1.55;
  color: var(--ink-soft);
}
.item-resurface-mark {
  font-style: normal;
  color: var(--accent);
  font-size: 1.1rem;
  line-height: 1.4;
  flex-shrink: 0;
}

/* ============================================================
 * Colophon
 * ============================================================ */
.colophon {
  margin-top: var(--space-4xl);
  text-align: center;
  font-family: var(--body);
  color: var(--ink-muted);
}
.colophon-rule {
  width: 4rem;
  height: 1px;
  background: var(--rule-strong);
  margin: 0 auto var(--space-xl);
}
.colophon-line {
  font-size: 0.72rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-sm);
  align-items: center;
  margin-bottom: var(--space-sm);
}
.colophon-line .dot { color: var(--ink-faint); }
.colophon-credit {
  text-transform: none;
  letter-spacing: 0.04em;
  font-style: italic;
  font-family: var(--body);
  font-weight: 400;
  font-size: 0.92rem;
  color: var(--ink-soft);
  margin-top: var(--space-md);
}
.colophon-credit strong {
  font-weight: 600;
  font-style: normal;
  color: var(--ink);
}

/* ============================================================
 * Responsive
 * ============================================================ */
@media (max-width: 640px) {
  .masthead {
    grid-template-columns: 1fr;
    text-align: center;
    gap: var(--space-md);
    padding-top: var(--space-sm);
  }
  .dateline, .issue-meta {
    justify-self: center;
    text-align: center;
  }
  .featured-summary::first-letter {
    font-size: 3.6rem;
  }
  .front-grid {
    gap: var(--space-xl);
  }
  .dispatch-gold {
    margin-left: calc(var(--space-md) * -1);
    margin-right: calc(var(--space-md) * -1);
    padding-left: var(--space-md);
    padding-right: var(--space-md);
  }
  .dispatch-header {
    grid-template-columns: 1fr;
    gap: var(--space-xs);
  }
  .dispatch-number { font-size: 2rem; }
}

/* ============================================================
 * Reduced motion + print
 * ============================================================ */
@media (prefers-reduced-motion: reduce) {
  * { transition: none !important; animation: none !important; }
}

@media print {
  body { max-width: none; padding: 1in; background: white; }
  a { color: var(--ink); text-decoration: none; }
  .dispatch-gold, .old-gold-aside { background: white; }
  .featured-hero, .item-hero { page-break-inside: avoid; }
}

