    } else if (fs.existsSync(path.join(personasDir, "default.yml"))) {
      personaName = "default";
    } else if (fs.existsSync(personasDir)) {
      const files = fs.readdirSync(personasDir).filter((f) => f.endsWith(".yml"));
      if (files.length === 1) {
        personaName = files[0].replace(".yml", "");
