1	// src/heartbeat.ts — Cron scheduler backed by pi-ai structured output + croner.
2	//
3	// Evening 3 of the pi-ai migration. What changed:
4	//
5	// - parseSchedule() now uses pi-agent-core's Agent class with a single
6	//   "submit_schedule" tool whose TypeBox schema forces the model to return
7	//   entries matching an exact shape. Replaces the old freeform-JSON-in-text
8	//   approach that had two failure modes:
9	//     1. `no JSON array found` when the model wrapped output in prose
10	//     2. Silent hallucination of phantom entries from explanatory prose
11	//        (e.g. a "system monitoring" entry that fired every minute in prod)
12	//
13	// - node-cron → croner. Same pattern strings, better DST handling, TS-native
14	//   types, smaller install.
15	//
16	// Public API (start, loadSchedule, listEntries, runNow) is unchanged —
17	// callers in index.ts and cli.ts don't need to change.
18	
19	import fs from "fs";
20	import path from "path";
21	import { Cron } from "croner";
22	import { Agent, type AgentTool } from "@mariozechner/pi-agent-core";
23	import {
24	  Type,
25	  getModel,
26	  type Api,
27	  type KnownProvider,
28	  type Model,
29	  type Static,
30	} from "@mariozechner/pi-ai";
31	import { think, type Turn } from "./agent.js";
32	import { MAME_HOME, type PersonaConfig, type MameConfig } from "./config.js";
33	import { parseModelString } from "./model-router.js";
34	import { childLogger } from "./logger.js";
35	
36	const log = childLogger("heartbeat");
37	
38	interface HeartbeatEntry {
39	  cron: string;
40	  prompt: string;
41	  project: string | null;
42	}
43	
44	// Schema for structured output — the schedule parser's model is forced to
45	// call submit_schedule with an array matching this shape. Validation is
46	// handled by pi-agent-core via TypeBox + AJV.
47	const ScheduleEntrySchema = Type.Object({
48	  cron: Type.String({
49	    description:
50	      "Standard 5-field cron expression (minute hour day-of-month month day-of-week). Examples: '30 7 * * *' for 7:30 AM daily, '*/15 * * * *' for every 15 minutes.",
51	  }),
52	  prompt: Type.String({
53	    description:
54	      "The task description the agent should run at this time. Combine related bullet points from the schedule document into one coherent prompt.",
55	  }),
56	  project: Type.Union([Type.String(), Type.Null()], {
57	    description:
58	      "A specific project name if the schedule explicitly scopes this task to one, otherwise null.",
59	  }),
60	});
61	
62	const ScheduleSchema = Type.Object({
63	  entries: Type.Array(ScheduleEntrySchema, {
64	    description:
65	      "The list of scheduled tasks extracted from the document. Include ONLY tasks that have an explicit schedule (time of day, interval, or cron spec). Skip anything that's explanatory prose or a future-feature note.",
66	  }),
67	});
68	
69	type ScheduleSchemaType = Static<typeof ScheduleSchema>;
70	
71	// --------------------------------------------------------------------------
72	// Testable parser core — accepts a pre-resolved pi-ai Model so offline tests
73	// can inject a faux-registered model without going through pi-ai's static
74	// getModel() catalog. The HeartbeatScheduler method below is a thin wrapper
75	// that handles model-string resolution via the persona config.
76	// --------------------------------------------------------------------------
77	export async function parseScheduleWithModel(
78	  piModel: Model<Api>,
79	  markdown: string
80	): Promise<HeartbeatEntry[]> {
81	  let captured: HeartbeatEntry[] | null = null;
82	
83	  const submitTool: AgentTool<typeof ScheduleSchema> = {
84	    name: "submit_schedule",
85	    label: "submit_schedule",
86	    description:
87	      "Submit the parsed schedule entries extracted from the document. Call this exactly once with all valid schedule entries you found. If the document contains no scheduled tasks, call it with an empty entries array.",
88	    parameters: ScheduleSchema,
89	    execute: async (_toolCallId, params: ScheduleSchemaType) => {
90	      captured = params.entries.map((e) => ({
91	        cron: e.cron,
92	        prompt: e.prompt,
93	        // AJV coerces Type.Union([String, Null]) nulls to "" in some
94	        // provider paths; treat empty strings as null so downstream code
95	        // sees the same "no project scope" sentinel regardless of model.
96	        project: e.project && e.project.length > 0 ? e.project : null,
97	      }));
98	      return {
99	        content: [
100	          {
101	            type: "text",
102	            text: `Captured ${params.entries.length} schedule entries.`,
103	          },
104	        ],
105	        details: params,
106	      };
107	    },
108	  };
109	
110	  const systemPrompt = `You are a schedule parser. Your only job is to read a natural-language schedule document and extract the scheduled tasks into a structured list.
111	
112	You MUST call the submit_schedule tool exactly once with all entries you found. Do not return any other text.
113	
114	RULES:
115	- ONLY include tasks that have an explicit schedule: a time of day ("every morning at 7:30"), an interval ("every 15 minutes"), or a cron spec.
116	- DO NOT hallucinate entries from explanatory prose, future-feature descriptions, or general discussion.
117	- DO NOT add entries for "system monitoring" or "health checks" unless they have an explicit schedule.
118	- If a section describes a feature but gives no schedule, SKIP it.
119	- Combine related bullet points under the same schedule into one coherent prompt string.
120	
121	Common pattern translations:
122	- "every morning at 7:30" → "30 7 * * *"
123	- "every evening at 18:30" → "30 18 * * *"
124	- "every day at 9 AM" → "0 9 * * *"
125	- "every 15 minutes" → "*/15 * * * *"
126	- "every hour" → "0 * * * *"
127	- "weekdays at 8 AM" → "0 8 * * 1-5"`;
128	
129	  const agent = new Agent({
130	    initialState: {
131	      systemPrompt,
132	      model: piModel,
133	      tools: [submitTool as AgentTool<any>],
134	      thinkingLevel: "off",
135	      messages: [],
136	    },
137	  });
138	
139	  try {
140	    await agent.prompt(
141	      `Parse this schedule document and call submit_schedule with the extracted entries:\n\n${markdown}`
142	    );
143	  } catch (err) {
144	    log.error(
145	      { err: err instanceof Error ? err.message : String(err) },
146	      "Schedule parser threw"
147	    );
148	    return [];
149	  }
150	
151	  if (agent.state.errorMessage) {
152	    log.error({ err: agent.state.errorMessage }, "Schedule parser error");
153	    return [];
154	  }
155	
156	  if (captured === null) {
157	    log.error(
158	      "Schedule parser did not call submit_schedule. The model returned text instead of invoking the tool. No entries loaded."
159	    );
160	    return [];
161	  }
162	
163	  return captured;
164	}
165	
166	export class HeartbeatScheduler {
167	  private jobs: Cron[] = [];
168	  private config: MameConfig;
169	  private persona: PersonaConfig;
170	  private notify: (project: string | undefined, message: string) => Promise<void>;
171	  private fileWatcher?: fs.FSWatcher;
172	
173	  constructor(
174	    config: MameConfig,
175	    persona: PersonaConfig,
176	    notify: (project: string | undefined, message: string) => Promise<void>
177	  ) {
178	    this.config = config;
179	    this.persona = persona;
180	    this.notify = notify;
181	  }
182	
183	  async start(): Promise<void> {
184	    const heartbeatPath = path.join(MAME_HOME, "HEARTBEAT.md");
185	
186	    if (!fs.existsSync(heartbeatPath)) {
187	      log.info("No HEARTBEAT.md found, skipping scheduler");
188	      return;
189	    }
190	
191	    await this.loadSchedule();
192	
193	    // Reload when HEARTBEAT.md changes
194	    this.fileWatcher = fs.watch(heartbeatPath, async (eventType) => {
195	      if (eventType === "change") {
196	        log.info("HEARTBEAT.md changed, reloading schedule");
197	        await this.loadSchedule();
198	      }
199	    });
200	  }
201	
202	  stop(): void {
203	    for (const job of this.jobs) {
204	      job.stop();
205	    }
206	    this.jobs = [];
207	    this.fileWatcher?.close();
208	  }
209	
210	  private async loadSchedule(): Promise<void> {
211	    // Clear existing jobs before reloading
212	    for (const job of this.jobs) {
213	      job.stop();
214	    }
215	    this.jobs = [];
216	
217	    const heartbeatPath = path.join(MAME_HOME, "HEARTBEAT.md");
218	    const raw = fs.readFileSync(heartbeatPath, "utf-8");
219	
220	    const entries = await this.parseSchedule(raw);
221	    const timezone = this.config.timezone || "Asia/Tokyo";
222	
223	    for (const entry of entries) {
224	      try {
225	        // croner validates the pattern in its constructor — throws on bad
226	        // input, which the catch below converts to a skip-with-warning.
227	        const job = new Cron(
228	          entry.cron,
229	          { timezone },
230	          async () => {
231	            log.info(
232	              { cron: entry.cron, prompt_preview: entry.prompt.slice(0, 50) },
233	              "Running scheduled check"
234	            );
235	
236	            const turn: Turn = {
237	              message: entry.prompt,
238	              channel: "heartbeat",
239	              project: entry.project || undefined,
240	              personaId: this.persona.name,
241	              soulFile: this.persona.soul,
242	              model: this.persona.models.heartbeat || this.persona.models.default,
243	              tools: this.persona.tools,
244	            };
245	
246	            const reply = await think(turn);
247	
248	            // Exact-match suppression only — if the model replies with
249	            // ALL_CLEAR as its entire response, treat the check as healthy.
250	            // Any response containing ALL_CLEAR as a substring still gets
251	            // delivered (a daily brief mentioning "everything's clear" is
252	            // still a daily brief).
253	            const trimmed = reply.trim();
254	            if (trimmed === "ALL_CLEAR" || trimmed === "ALL_CLEAR.") {
255	              log.info(
256	                { cron: entry.cron, prompt_preview: entry.prompt.slice(0, 50) },
257	                "Suppressed (ALL_CLEAR)"
258	              );
259	              return;
260	            }
261	
262	            await this.notify(entry.project || undefined, `💓 ${reply}`);
263	          }
264	        );
265	
266	        this.jobs.push(job);
267	      } catch (err) {
268	        log.error(
269	          { cron: entry.cron, err: err instanceof Error ? err.message : String(err) },
270	          "Invalid cron expression, skipping"
271	        );
272	      }
273	    }
274	
275	    log.info({ count: this.jobs.length }, `Loaded ${this.jobs.length} scheduled checks`);
276	  }
277	
278	  private async parseSchedule(markdown: string): Promise<HeartbeatEntry[]> {
279	    const modelStr = this.persona.models.heartbeat || this.persona.models.default;
280	    const route = parseModelString(modelStr);
281	
282	    let piModel;
283	    try {
284	      piModel = getModel(route.backend as KnownProvider as any, route.modelId as any);
285	    } catch (err) {
286	      log.error(
287	        { model: modelStr, err: err instanceof Error ? err.message : String(err) },
288	        "Model lookup failed"
289	      );
290	      return [];
291	    }
292	    if (!piModel) {
293	      log.error({ model: modelStr }, "Model not registered in pi-ai catalog");
294	      return [];
295	    }
296	
297	    return parseScheduleWithModel(piModel, markdown);
298	  }
299	
300	  // List the parsed schedule entries (for CLI inspection)
301	  async listEntries(): Promise<HeartbeatEntry[]> {
302	    const heartbeatPath = path.join(MAME_HOME, "HEARTBEAT.md");
303	    if (!fs.existsSync(heartbeatPath)) return [];
304	    const raw = fs.readFileSync(heartbeatPath, "utf-8");
305	    return this.parseSchedule(raw);
306	  }
307	
308	  // Run all scheduled entries immediately (for manual testing via CLI)
309	  async runNow(): Promise<string> {
310	    const entries = await this.listEntries();
311	    if (entries.length === 0) {
312	      return "No HEARTBEAT.md entries to run.";
313	    }
314	
315	    const results: string[] = [];
316	    for (const entry of entries) {
317	      log.info(
318	        { cron: entry.cron, prompt_preview: entry.prompt.slice(0, 60) },
319	        "Running scheduled check (manual)"
320	      );
321	
322	      const turn: Turn = {
323	        message: entry.prompt,
324	        channel: "heartbeat",
325	        project: entry.project || undefined,
326	        personaId: this.persona.name,
327	        soulFile: this.persona.soul,
328	        model: this.persona.models.heartbeat || this.persona.models.default,
329	        tools: this.persona.tools,
330	      };
331	
332	      const reply = await think(turn);
333	      const trimmed = reply.trim();
334	
335	      if (trimmed === "ALL_CLEAR" || trimmed === "ALL_CLEAR.") {
336	        results.push(`✓ [${entry.cron}] ALL_CLEAR (suppressed)`);
337	        continue;
338	      }
339	
340	      await this.notify(entry.project || undefined, `💓 ${reply}`);
341	      results.push(`✓ [${entry.cron}] Delivered`);
342	    }
343	
