1	// src/config.ts — Load config + persona with runtime validation via zod.
2	//
3	// Evening 4 of the pi-ai migration. Previously loadConfig() and
4	// loadPersona() did a raw TypeScript cast (`parse(raw) as MameConfig`)
5	// with no runtime checks, which meant a typo in config.yml or a missing
6	// required field would crash somewhere deep in the daemon with a cryptic
7	// "undefined is not a function" message.
8	//
9	// Now we parse through zod schemas that both validate structure AND
10	// generate the TypeScript types via z.infer, so there's only one source
11	// of truth per interface. Malformed config fails at startup with a clear,
12	// path-scoped error message.
13	
14	import fs from "fs";
15	import path from "path";
16	import { parse } from "yaml";
17	import { z } from "zod";
18	
19	export const MAME_HOME = process.env.MAME_HOME || path.join(process.env.HOME || "~", ".mame");
20	
21	// ---------------------------------------------------------------------------
22	// Schemas — one per interface. Zod does runtime validation; z.infer below
23	// gives us the TypeScript types for free, so nothing else needs to change.
24	// ---------------------------------------------------------------------------
25	
26	const ProjectConfigSchema = z.object({
27	  path: z.string(),
28	  github: z.string().optional(),
29	});
30	
